/* BTDirection — form panel organism.
   Figma: node 2504-3364.
   Shared between @btech/ui-vue and @btech/ui-react — keep both copies identical.
   All colors via CSS token vars — no hex fallbacks (CLAUDE.md §6). */

/* ── Container ─────────────────────────────────────────────────────────────── */

.bt-direction {
  display: flex;
  flex-direction: column;
  width: 500px;
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-elevation-md);
  overflow: hidden;
  font-family: var(--typography-font-family-sans);
}

/* ── Header section (title + optional subtext + slot) ─────────────────────── */

.bt-direction__header {
  display: flex;
  flex-direction: column;
  gap: var(--space-lg);
  padding: var(--space-lg);
  background: var(--bg-primary);
}

/* Row: title block (flex-1) + optional top-right link */
.bt-direction__header-row {
  display: flex;
  align-items: flex-start;
  gap: 10px;
}

.bt-direction__title-block {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  flex: 1 0 0;
  min-width: 0;
}

.bt-direction__title {
  font-size: var(--typography-font-size-lg);
  font-weight: 700;
  line-height: var(--typography-line-height-md);
  color: var(--text-primary);
  margin: 0;
}

.bt-direction__subtext {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  margin: 0;
}

/* Content slot — vertical stack with 12px gap */
.bt-direction__slot {
  display: flex;
  flex-direction: column;
  gap: var(--space-md);
}

/* Direct slotted native controls only — do not restyle BTInput internals */
.bt-direction__slot > :is(
  input:not([type='checkbox']):not([type='radio']):not([type='hidden']),
  textarea,
  select
) {
  width: 100%;
  box-sizing: border-box;
  height: 50px;
  padding: 0 var(--space-sm);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  background: var(--bg-primary);
  color: var(--text-primary);
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-direction__slot > textarea {
  height: auto;
  min-height: 100px;
  padding: var(--space-sm);
}

.bt-direction__slot > :is(input, textarea)::placeholder {
  color: var(--text-secondary);
}

[data-mode='dark'] .bt-direction__slot > :is(input, textarea, select) {
  color-scheme: dark;
}

/* ── Footer section (stacked full-width buttons) ──────────────────────────── */

.bt-direction__footer {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
  padding: var(--space-lg);
  background: var(--bg-subtle);
}

/* Force BTButton children to fill the full footer width */
.bt-direction__footer .bt-button {
  width: 100%;
  justify-content: center;
}

/**
 * BTDirection — form panel organism with header, content slot, and footer.
 * Figma: node 2504-3364.
 *
 * @example
 * ```tsx
 * import { BTDirection } from '@btech/ui-react';
 *
 * export function Example() {
 *   return (
 *     <BTDirection
 *       title="Edit Profile"
 *       subtext="Update your information below."
 *       linkLabel="Need help?"
 *       primaryLabel="Save"
 *       secondaryLabel="Cancel"
 *       onPrimary={handleSave}
 *       onSecondary={handleCancel}
 *       onLinkClick={openHelp}
 *     >
 *       <BTInput label="Name" value={name} onChange={setName} />
 *       <BTInput label="Email" value={email} onChange={setEmail} />
 *     </BTDirection>
 *   );
 * }
 * ```
 */
import type { ReactNode } from 'react';
import './BTDirection.css';
import type { BTDirectionProps } from './BTDirection.types';
import { BTButton } from '../button/BTButton';
import { BTButtonLink } from '../button-link/BTButtonLink';

interface BTDirectionReactProps extends BTDirectionProps {
  children?: ReactNode;
  onPrimary?: () => void;
  onSecondary?: () => void;
  onLinkClick?: () => void;
  className?: string;
}

export function BTDirection({
  title,
  subtext,
  linkLabel,
  primaryLabel,
  secondaryLabel,
  children,
  onPrimary,
  onSecondary,
  onLinkClick,
  className,
}: BTDirectionReactProps) {
  const rootClass = ['bt-direction', className].filter(Boolean).join(' ');

  return (
    <div className={rootClass} data-testid="bt-direction">
      {/* White header section */}
      <div className="bt-direction__header">
        <div className="bt-direction__header-row">
          <div className="bt-direction__title-block">
            <p className="bt-direction__title">{title}</p>
            {subtext && <p className="bt-direction__subtext">{subtext}</p>}
          </div>
          {linkLabel && (
            <BTButtonLink label={linkLabel} onClick={onLinkClick} />
          )}
        </div>
        {/* Content slot */}
        <div className="bt-direction__slot">{children}</div>
      </div>

      {/* Grey footer section */}
      <div className="bt-direction__footer">
        <BTButton label={primaryLabel} onClick={onPrimary} />
        {secondaryLabel && (
          <BTButton
            label={secondaryLabel}
            variant="secondary-light"
            onClick={onSecondary}
          />
        )}
      </div>
    </div>
  );
}
BTDirection.displayName = 'BTDirection';

/**
 * BTDirection — form panel organism with header, content slot, and footer.
 * Figma: node 2504-3364.
 *
 * Stateless layout container — no internal state.
 * Caller owns all interaction logic (click handlers, form state).
 */
export interface BTDirectionProps {
  // ── Header ─────────────────────────────────────────────────────────────────
  /** Bold heading (18px) in the header section. */
  title: string;
  /** Supporting text below the title. Hidden when not provided. */
  subtext?: string;

  // ── Top-right link ─────────────────────────────────────────────────────────
  /**
   * Label for the optional link in the top-right corner of the header.
   * Vue/React: hidden when not provided.
   * Flutter: hidden when onLinkPressed is null.
   */
  linkLabel?: string;

  // ── Footer buttons ──────────────────────────────────────────────────────────
  /** Label for the primary footer button (brand colour, full-width). */
  primaryLabel: string;
  /**
   * Label for the secondary footer button (neutral, full-width).
   * Vue/React: hidden when not provided.
   * Flutter: hidden when onSecondaryPressed is null.
   */
  secondaryLabel?: string;
}
